const fs = require('fs');
const path = require('path');
const config = $('Runtime Config').first().json;
const repoPath = config.repoPath;
const phaseDir = path.join(repoPath, 'docs/editorial-phase-0');
const pipelineDir = path.join(repoPath, 'docs/editorial-pipeline');
const read = (rel) => fs.readFileSync(path.join(repoPath, rel), 'utf8');
const dryRunSlug = (config.dryRunSlug || '').trim();
const phaseFiles = fs.readdirSync(phaseDir).filter(f => f.endsWith('.md')).sort();
const done = new Set();
if (fs.existsSync(pipelineDir)) {
  for (const folder of fs.readdirSync(pipelineDir)) {
    const logPath = path.join(pipelineDir, folder, 'run-log.json');
    if (fs.existsSync(logPath)) {
      try { const log = JSON.parse(fs.readFileSync(logPath, 'utf8')); if (log.slug) done.add(log.slug); } catch (e) {}
    }
  }
}
let file = dryRunSlug ? `${dryRunSlug}.md` : phaseFiles.find(f => !done.has(f.replace(/\.md$/, '')));
let needsHumanTopicExpansion = false;
if (!file || !fs.existsSync(path.join(phaseDir, file))) {
  file = phaseFiles[0];
  needsHumanTopicExpansion = true;
}
const slug = file.replace(/\.md$/, '');
const today = new Date().toISOString().slice(0, 10);
const runFolder = `docs/editorial-pipeline/${today}-${slug}`;
return [{ json: {
  ...config,
  slug,
  topicFile: `docs/editorial-phase-0/${file}`,
  topicMarkdown: fs.readFileSync(path.join(phaseDir, file), 'utf8'),
  contentPlan: read('docs/seo-geo-content-plan.md'),
  styleGuide: read('docs/raphaelbaruch-style.md'),
  framerContract: read('docs/framer-cms-field-contract.md'),
  orchestratorPrompt: read('automations/n8n/prompts/orchestrator.md'),
  writerPrompt: read('automations/n8n/prompts/writer.md'),
  editorPrompt: read('automations/n8n/prompts/editor-validator.md'),
  runFolder,
  needsHumanTopicExpansion,
  selectedTopicReason: dryRunSlug ? `Manual dry run slug: ${dryRunSlug}` : `First unpublished Phase-0 topic: ${slug}`
}}];

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');
const base = $('Select Next Topic').first().json;
const repoPath = base.repoPath;
const runDir = path.join(repoPath, base.runFolder);
fs.mkdirSync(runDir, { recursive: true });
function raw(name) { try { return $(name).first().json; } catch (e) { return null; } }
function text(name) { const value = raw(name); if (!value) return ''; if (value.content && value.content[0] && value.content[0].text) return value.content[0].text; if (value.choices && value.choices[0] && value.choices[0].message) return value.choices[0].message.content; return JSON.stringify(value, null, 2); }
function write(name, value) { if (value) fs.writeFileSync(path.join(runDir, name), value); }
function approved(review) { return review.includes('"approved": true') || review.includes('"approved":true'); }
function extractPayload(markdown) { const fenced = markdown.match(/## Framer CMS JSON[\s\S]*?```json\s*([\s\S]*?)```/i) || markdown.match(/```json\s*([\s\S]*?)```/i); if (!fenced) return {}; try { return JSON.parse(fenced[1]); } catch (e) { return {}; } }
const review3 = text('OpenAI Editor Review v3');
const review2 = text('OpenAI Editor Review v2');
const review1 = text('OpenAI Editor Review v1');
const draft3 = text('Anthropic Writer Draft v3');
const draft2 = text('Anthropic Writer Draft v2');
const draft1 = text('Anthropic Writer Draft v1');
const approved1 = approved(review1);
const approved2 = approved(review2);
const approved3 = approved(review3);
const finalDraft = approved1 ? draft1 : (approved2 ? draft2 : (draft3 || draft2 || draft1));
const finalReview = approved1 ? review1 : (approved2 ? review2 : (review3 || review2 || review1));
const isApproved = approved1 || approved2 || approved3;
write('brief.md', text('Anthropic Orchestrator Brief'));
write('draft-v1.md', draft1);
write('draft-v2.md', draft2);
write('draft-v3.md', draft3);
write('editor-review-v1.md', review1);
write('editor-review-v2.md', review2);
write('editor-review-v3.md', review3);
write('final.md', finalDraft);
const extracted = extractPayload(finalDraft);
const payload = {
  'Title': extracted['Title'] || base.slug,
  'Slug': extracted['Slug'] || base.slug,
  'Meta Title': extracted['Meta Title'] || extracted['Title'] || base.slug,
  'Meta Description': extracted['Meta Description'] || extracted['Excerpt'] || '',
  'Excerpt': extracted['Excerpt'] || '',
  'Primary Keyword': extracted['Primary Keyword'] || '',
  'Secondary Keywords': extracted['Secondary Keywords'] || [],
  'Longtail Keywords': extracted['Longtail Keywords'] || [],
  'Article Body': extracted['Article Body'] || finalDraft,
  'FAQ': extracted['FAQ'] || [],
  'Video Brief': extracted['Video Brief'] || '',
  'Carousel Brief': extracted['Carousel Brief'] || '',
  'Status': 'Draft',
  'Review Notes': (extracted['Review Notes'] || '') + '\n\nEditor status: ' + (isApproved ? 'approved' : 'needs human decision after max 3 rounds') + '\n' + finalReview
};
write('framer-payload.json', JSON.stringify(payload, null, 2));
const log = { slug: base.slug, runFolder: base.runFolder, approved: isApproved, needs_human_decision: !isApproved, selectedTopicReason: base.selectedTopicReason, createdAt: new Date().toISOString() };
write('run-log.json', JSON.stringify(log, null, 2));
execSync(`git add ${base.runFolder}`, { cwd: repoPath, stdio: 'inherit' });
execSync(`git commit -m "Add editorial draft: ${base.slug}"`, { cwd: repoPath, stdio: 'inherit' });
execSync('git push', { cwd: repoPath, stdio: 'inherit' });
return [{ json: { ...base, ...log, framerPayload: payload, artifactPath: base.runFolder, artifactUrl: `${base.githubArtifactBaseUrl}/${base.runFolder}` } }];
